/* filepath: c:\MERN-FIA-PORTAL\client\src\components\AboutSection.js */
import React, { useEffect, useRef, useState } from 'react';
import { Link } from 'react-router-dom';
import '../styles/AboutSection.css';

const AboutSection = ({ showAllFeatures = false }) => {
    const sectionRef = useRef(null);
    const [activeFeature, setActiveFeature] = useState(null);
    const [isVisible, setIsVisible] = useState(false);

    // Enhanced scroll animation effect
    useEffect(() => {
        const observer = new IntersectionObserver((entries) => {
            entries.forEach(entry => {
                if (entry.isIntersecting) {
                    setIsVisible(true);
                    entry.target.classList.add('visible');
                }
            });
        }, { threshold: 0.1 });

        if (sectionRef.current) {
            observer.observe(sectionRef.current);
        }

        return () => {
            if (sectionRef.current) {
                observer.unobserve(sectionRef.current);
            }
        };
    }, []);

    // Enhanced core features with better content and icons
    const coreFeatures = [
        {
            icon: "business_center",
            title: "Industry Excellence",
            description: "Partner with leading tech companies and gain access to exclusive opportunities that set you apart in the competitive job market.",
            highlight: "300+ Partner Companies",
            color: "#2563eb",
            stats: "95% placement rate"
        },
        {
            icon: "school",
            title: "Expert Faculty",
            description: "Learn from industry veterans and certified professionals who bring real-world experience directly to your learning journey.",
            highlight: "20+ Years Experience",
            color: "#059669",
            stats: "PhD & Industry Certified"
        },
        {
            icon: "computer",
            title: "Modern Infrastructure",
            description: "Access state-of-the-art labs, cutting-edge technology, and professional-grade development environments.",
            highlight: "¥500M Investment",
            color: "#dc2626",
            stats: "Latest Tech Stack"
        },
        {
            icon: "trending_up",
            title: "Career Success",
            description: "Comprehensive career support from portfolio development to interview preparation and job placement assistance.",
            highlight: "98% Success Rate",
            color: "#7c3aed",
            stats: "Lifetime Support"
        }
    ];

    // Additional premium features
    const additionalFeatures = [
        {
            icon: "verified_user",
            title: "Industry Certifications",
            description: "Earn globally recognized certifications from AWS, Google, Microsoft, and other leading technology providers.",
            highlight: "12+ Certifications",
            color: "#0891b2",
            stats: "100% Pass Rate"
        },
        {
            icon: "support_agent",
            title: "Personal Mentorship",
            description: "One-on-one guidance from experienced mentors who help you navigate your career path and achieve your goals.",
            highlight: "1:1 Mentoring",
            color: "#ea580c",
            stats: "24/7 Available"
        }
    ];

    const displayFeatures = showAllFeatures ? 
        [...coreFeatures, ...additionalFeatures] : 
        coreFeatures;

    const testimonials = [
        {
            quote: "FIA transformed my career completely. The hands-on approach and industry connections opened doors I never thought possible.",
            author: "Yuki Tanaka",
            role: "Senior Developer at Google Japan",
            image: "/images/testimonial1.jpg",
            year: "Class of 2024"
        },
        {
            quote: "The mentorship program and career support helped me land my dream job at a top tech startup within weeks of graduation.",
            author: "Hiroshi Sato",
            role: "Full-Stack Engineer at StartupTech",
            image: "/images/testimonial2.jpg",
            year: "Class of 2023"
        }
    ];

    const [currentTestimonial, setCurrentTestimonial] = useState(0);

    // Auto-rotate testimonials
    useEffect(() => {
        if (testimonials.length > 1) {
            const interval = setInterval(() => {
                setCurrentTestimonial(prev => (prev + 1) % testimonials.length);
            }, 5000);
            return () => clearInterval(interval);
        }
    }, []);

    return (
        <section className="about-section" id="about" ref={sectionRef}>
            {/* Enhanced background elements */}
            <div className="about-background">
                <div className="about-gradient"></div>
                <div className="about-patterns">
                    <div className="pattern-dot"></div>
                    <div className="pattern-circle"></div>
                    <div className="pattern-triangle"></div>
                </div>
            </div>

            <div className="about-container">
                {/* Enhanced section header */}
                <div className="about-header">
                    <div className="header-badge">
                        <span className="material-icons">star</span>
                        Your Success Journey
                    </div>
                    <h2 className="header-title">
                        Why Choose <span className="highlight">FIA</span>?
                    </h2>
                    <p className="header-description">
                        Discover what makes Forum Information Academy the premier destination 
                        for tech education in Japan. Our proven approach combines academic 
                        excellence with industry expertise.
                    </p>
                </div>

                {/* Enhanced features grid */}
                <div className="features-section">
                    <div className="features-grid">
                        {displayFeatures.map((feature, index) => (
                            <div 
                                className={`feature-card ${activeFeature === index ? 'active' : ''}`}
                                key={index} 
                                style={{
                                    animationDelay: `${index * 0.15}s`,
                                    opacity: isVisible ? 1 : 0,
                                    transform: isVisible ? 'translateY(0)' : 'translateY(30px)'
                                }}
                                onMouseEnter={() => setActiveFeature(index)}
                                onMouseLeave={() => setActiveFeature(null)}
                            >
                                <div className="feature-header">
                                    <div className="feature-icon" style={{ backgroundColor: `${feature.color}15` }}>
                                        <span className="material-icons" style={{ color: feature.color }}>
                                            {feature.icon}
                                        </span>
                                    </div>
                                    <div className="feature-stats" style={{ color: feature.color }}>
                                        {feature.stats}
                                    </div>
                                </div>

                                <div className="feature-content">
                                    <h3 className="feature-title">{feature.title}</h3>
                                    <p className="feature-description">{feature.description}</p>

                                    <div className="feature-highlight" style={{ backgroundColor: `${feature.color}10` }}>
                                        <span className="highlight-icon material-icons">trending_up</span>
                                        <span className="highlight-text" style={{ color: feature.color }}>
                                            {feature.highlight}
                                        </span>
                                    </div>
                                </div>

                                <div className="feature-overlay" style={{ background: `linear-gradient(135deg, ${feature.color}15, ${feature.color}08)` }}></div>
                            </div>
                        ))}
                    </div>
                </div>

                {/* Enhanced CTA section */}
                {!showAllFeatures && (
                    <div className="cta-section">
                        <div className="cta-card">
                            <div className="cta-content">
                                <div className="cta-badge">
                                    <span className="material-icons">explore</span>
                                    Discover More
                                </div>
                                <h3 className="cta-title">Ready to Transform Your Future?</h3>
                                <p className="cta-description">
                                    Join thousands of successful graduates who chose FIA to launch their tech careers. 
                                    Explore our comprehensive programs and see why we're Japan's leading tech academy.
                                </p>

                                <div className="cta-stats-grid">
                                    <div className="cta-stat">
                                        <div className="stat-number">15+</div>
                                        <div className="stat-label">Years Excellence</div>
                                    </div>
                                    <div className="cta-stat">
                                        <div className="stat-number">8,000+</div>
                                        <div className="stat-label">Graduates</div>
                                    </div>
                                    <div className="cta-stat">
                                        <div className="stat-number">98%</div>
                                        <div className="stat-label">Job Placement</div>
                                    </div>
                                </div>

                                <div className="cta-actions">
                                    <Link to="/about" className="btn-primary">
                                        <span>Explore Our Story</span>
                                        <span className="material-icons">arrow_forward</span>
                                    </Link>
                                    <Link to="/programs" className="btn-secondary">
                                        <span>View Programs</span>
                                        <span className="material-icons">school</span>
                                    </Link>
                                </div>
                            </div>

                            <div className="cta-visual">
                                <div className="visual-content">
                                    <img src="/images/campus-modern.jpg" alt="FIA Campus" className="cta-image" />
                                    <div className="visual-overlay">
                                        <div className="play-button">
                                            <span className="material-icons">play_arrow</span>
                                        </div>
                                        <div className="visual-text">Take a Virtual Tour</div>
                                    </div>
                                </div>
                            </div>
                        </div>
                    </div>
                )}

                {/* Enhanced testimonial section */}
                <div className="testimonial-section">
                    <div className="testimonial-header">
                        <h3>What Our Graduates Say</h3>
                        <div className="testimonial-nav">
                            {testimonials.map((_, index) => (
                                <button
                                    key={index}
                                    className={`nav-dot ${currentTestimonial === index ? 'active' : ''}`}
                                    onClick={() => setCurrentTestimonial(index)}
                                />
                            ))}
                        </div>
                    </div>

                    <div className="testimonial-card">
                        <div className="testimonial-content">
                            <div className="quote-icon">
                                <span className="material-icons">format_quote</span>
                            </div>
                            <blockquote className="testimonial-quote">
                                {testimonials[currentTestimonial].quote}
                            </blockquote>

                            <div className="testimonial-author">
                                <img 
                                    src={testimonials[currentTestimonial].image} 
                                    alt={testimonials[currentTestimonial].author}
                                    className="author-image"
                                />
                                <div className="author-info">
                                    <div className="author-name">{testimonials[currentTestimonial].author}</div>
                                    <div className="author-role">{testimonials[currentTestimonial].role}</div>
                                    <div className="author-year">{testimonials[currentTestimonial].year}</div>
                                </div>
                            </div>
                        </div>
                    </div>
                </div>
            </div>
        </section>
    );
};

export default AboutSection;
